
.trait {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 2px 0;
}
.trait-head {
  display: flex;
  align-items: center;
  gap: 2px;
  min-width: 54px;
}
.trait-label {
  font-size: 9px;
  color: var(--text-label);
  font-weight: 500;
  white-space: nowrap;
}
.trait-bar {
  display: flex;
  gap: 2px;
  flex: 1;
}
.trait-seg {
  flex: 1;
  height: 8px;
  border-radius: 3px;
  background: rgba(155, 138, 155, 0.12);
  transition: all 0.3s ease;
}
.trait-seg.filled {
  background: var(--seg-color, var(--c-illya));
  box-shadow: 0 0 4px color-mix(in srgb, var(--seg-color, var(--c-illya)) 30%, transparent);
}
.trait-val {
  min-width: 22px;
  text-align: right;
  font-size: 9px;
  font-variant-numeric: tabular-nums;
  color: var(--text-secondary);
}
